        id: 'css',
        label: 'styles.css',
        language: 'css',
        sourcePath:
          'angular/apps/demo-angular/src/app/features/packages/angular/angular-query-form/pages/recovery-query-form-demo-page/recovery-query-form-demo-page.component.css',
        code: ':host {\n  display: block;\n}\n\n.recovery-actions,\n.recovery-pager,\n.recovery-view-row {\n  display: flex;\n  gap: 0.8rem;\n  align-items: center;\n  flex-wrap: wrap;\n}\n\n.recovery-controls-grid {\n  display: grid;\n  gap: 1rem;\n  grid-template-columns: repeat(auto-fit, minmax(13rem, 1fr));\n}\n\n.recovery-field--wide,\n.recovery-view-fieldset {\n  grid-column: 1 / -1;\n}\n\n.recovery-view-fieldset {\n  display: grid;\n  gap: 0.75rem;\n  margin: 0;\n  padding: 0;\n  border: 0;\n}\n\n.recovery-view-fieldset legend {\n  padding: 0;\n  margin-bottom: 0.2rem;\n  color: var(--color-ink);\n  font-size: 0.92rem;\n  font-weight: 600;\n}\n\n.recovery-results-head {\n  display: flex;\n  gap: 1rem;\n  align-items: center;\n  justify-content: space-between;\n  flex-wrap: wrap;\n}\n\n.recovery-results-summary,\n.recovery-incident-card p {\n  margin: 0;\n  color: var(--color-muted);\n}\n\n.recovery-incident-grid {\n  display: grid;\n  gap: 1rem;\n  grid-template-columns: repeat(auto-fit, minmax(15rem, 1fr));\n}\n\n.recovery-incident-card {\n  display: grid;\n  gap: 0.7rem;\n  padding: 1.2rem;\n  border: 1px solid var(--color-border);\n  border-radius: 1.15rem;\n  background: color-mix(in srgb, var(--color-surface-strong) 82%, white);\n  box-shadow: var(--shadow-soft);\n}\n\n.recovery-incident-card__head {\n  display: flex;\n  gap: 0.75rem;\n  align-items: center;\n  justify-content: space-between;\n  flex-wrap: wrap;\n}\n\n.recovery-incident-card h4 {\n  margin: 0;\n}\n\n.recovery-incident-card strong,\n.recovery-empty-state {\n  color: var(--color-ink);\n}\n\n.recovery-severity-chip {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  padding: 0.28rem 0.62rem;\n  border-radius: 999px;\n  border: 1px solid rgba(138, 79, 0, 0.16);\n  background: linear-gradient(180deg, rgba(255, 191, 120, 0.22), rgba(217, 119, 75, 0.12));\n  color: #8a4f00;\n  font-size: 0.72rem;\n  text-transform: uppercase;\n  letter-spacing: 0.08em;\n}\n\n.recovery-incident-detail {\n  line-height: 1.5;\n}\n\n.recovery-empty-state {\n  padding: 1.4rem;\n  border-radius: 1rem;\n  background: color-mix(in srgb, var(--color-surface-strong) 84%, white);\n}\n\n@media (max-width: 720px) {\n  .recovery-pager {\n    width: 100%;\n    justify-content: space-between;\n  }\n}',
