        id: 'css',
        label: 'styles.css',
        language: 'css',
        sourcePath:
          'angular/apps/demo-angular/src/app/features/packages/angular/angular-lookups/pages/lookups-editor-demo-page/lookups-editor-demo-page.component.css',
        code: '.lookups-toolbar {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 0.75rem;\n  justify-content: flex-end;\n}\n\n.lookups-action-row {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 0.75rem;\n}\n\n.lookups-banner {\n  margin: 0;\n  padding: 0.875rem 1rem;\n  border-radius: 0.9rem;\n  background: #fff4db;\n  color: #725004;\n}\n\n.lookups-banner--warning {\n  border: 1px solid #e0c37d;\n}\n\n.lookups-surface-grid {\n  display: grid;\n  gap: 1rem;\n}\n\n.lookups-surface-card,\n.lookups-collection-card {\n  display: grid;\n  gap: 0.9rem;\n  padding: 1.25rem;\n  border-radius: 1rem;\n  background: #f7fafc;\n}\n\n.lookups-select-grid {\n  display: grid;\n  gap: 1rem;\n}\n\n.lookups-selection-list {\n  margin: 0;\n  padding-left: 1.1rem;\n  display: grid;\n  gap: 0.5rem;\n}\n\n.lookups-collection-grid {\n  display: grid;\n  gap: 1rem;\n  grid-template-columns: repeat(auto-fit, minmax(10rem, 1fr));\n}\n\n@media (min-width: 900px) {\n  .lookups-surface-grid {\n    grid-template-columns: minmax(0, 1.35fr) minmax(0, 1fr);\n  }\n\n  .lookups-select-grid {\n    grid-template-columns: repeat(3, minmax(0, 1fr));\n  }\n}',
