          'angular/apps/demo-angular/src/app/features/packages/angular/angular-lookups/pages/lookups-backend-demo-page/lookups-backend-demo-page.component.html',
        code: '<demo-page-layout testId="lookups-backend-page">\n  <demo-navigation-strip demoNavigation testId="lookups-backend-demo-navigation" [demo]="demo" />\n\n  <article demoIntro class="demo-card demo-card--stack" data-testid="lookups-backend-intro-card">\n    <div class="demo-card__header">\n      <div>\n        <p class="demo-eyebrow">Angular Lookups + .NET sample API</p>\n        <h2>\n          One shared backend endpoint feeds the Angular lookup cache through a real browser request.\n        </h2>\n      </div>\n\n      <div class="lookups-toolbar">\n        <span class="demo-hint-pill" data-testid="lookups-backend-version-pill">\n          Version: {{ lookups.version() ?? \'not loaded\' }}\n        </span>\n        <span class="demo-hint-pill" data-testid="lookups-backend-request-count-pill">\n          Requests: {{ repository.loadCount() }}\n        </span>\n      </div>\n    </div>\n\n    <p class="demo-card__summary">\n      This page keeps the Angular integration thin: <code>provideHexGuardLookups()</code> still owns\n      the cache, but the loader performs a real cross-origin fetch to the shared .NET sample API\n      under <code>/api/angular-lookups/catalog</code>.\n    </p>\n\n    <div class="lookups-connection-grid">\n      <label class="demo-field">\n        <span>Sample API origin</span>\n        <input\n          class="demo-input"\n          [ngModel]="apiBaseUrl()"\n          data-testid="lookups-backend-api-base-url-input"\n          (ngModelChange)="updateApiBaseUrl($event)"\n        />\n      </label>\n\n      <label class="demo-field">\n        <span>Catalog scenario</span>\n        <select\n          class="demo-select"\n          [ngModel]="selectedScenario()"\n          data-testid="lookups-backend-scenario-select"\n          [disabled]="isBusy()"\n          (ngModelChange)="updateScenario($event)"\n        >\n          @for (scenario of scenarioOptions; track scenario.value) {\n            <option [value]="scenario.value">{{ scenario.label }}</option>\n          }\n        </select>\n      </label>\n    </div>\n\n    <div class="lookups-action-row">\n      <button\n        type="button"\n        class="demo-button"\n        data-testid="lookups-backend-load-button"\n        [disabled]="isBusy()"\n        (click)="loadSelectedScenario()"\n      >\n        Load selected scenario\n      </button>\n      <button\n        type="button"\n        class="demo-button demo-button--ghost"\n        data-testid="lookups-backend-reload-button"\n        [disabled]="!lookupState.hasLoaded() || isBusy()"\n        (click)="reloadSelectedScenario()"\n      >\n        Reload current scenario\n      </button>\n      <button\n        type="button"\n        class="demo-button demo-button--ghost"\n        data-testid="lookups-backend-invalidate-button"\n        (click)="invalidateCatalog()"\n      >\n        Invalidate cache\n      </button>\n    </div>\n\n    @if (requestUrl(); as requestUrl) {\n      <p class="lookups-request-url" data-testid="lookups-backend-request-url">\n        Request URL: {{ requestUrl }}\n      </p>\n    }\n\n    @if (errorMessage(); as errorMessage) {\n      <p class="lookups-banner lookups-banner--warning" data-testid="lookups-backend-error">\n        {{ errorMessage }}\n      </p>\n    }\n\n    <demo-status-strip\n      testId="lookups-backend-status-strip"\n      summaryTestId="lookups-backend-summary"\n      urlTestId="lookups-backend-current-url"\n      [summary]="statusSummary()"\n      [currentUrl]="currentUrl()"\n    />\n  </article>\n\n  <article demoPrimary class="demo-card demo-card--stack" data-testid="lookups-backend-grid-card">\n    <div class="lookups-surface-grid">\n      <section class="lookups-surface-card" data-testid="lookups-backend-contract-panel">\n        <p class="demo-eyebrow">Integration contract</p>\n        <h3>One package-scoped backend route, one shared cache facade</h3>\n\n        <ul class="lookups-selection-list">\n          <li data-testid="lookups-backend-endpoint-path">\n            Endpoint: /api/angular-lookups/catalog\n          </li>\n          <li data-testid="lookups-backend-active-scenario">Scenario: {{ selectedScenario() }}</li>\n          <li data-testid="lookups-backend-active-version">\n            Catalog version: {{ lookups.version() ?? \'not loaded\' }}\n          </li>\n          <li data-testid="lookups-backend-request-total">\n            Requests made: {{ repository.loadCount() }}\n          </li>\n        </ul>\n\n        <p class="demo-card__summary">\n          The same <code>LookupCatalog</code> contract powers the sample API and the Angular label\n          resolver, so refreshed labels and invalid payloads are visible without writing page-local\n          mapping code.\n        </p>\n      </section>\n\n      <section class="lookups-surface-card" data-testid="lookups-backend-grid">\n        <p class="demo-eyebrow">Live backend labels</p>\n        <h3>Template rendering stays unchanged even when the backend scenario changes</h3>\n\n        <div class="lookups-table-shell">\n          <table class="lookups-table">\n            <thead>\n              <tr>\n                <th scope="col">SKU</th>\n                <th scope="col">Product</th>\n                <th scope="col">Category</th>\n                <th scope="col">Supplier</th>\n                <th scope="col">Lifecycle</th>\n              </tr>\n            </thead>\n            <tbody>\n              @for (product of products; track product.sku) {\n                <tr [attr.data-testid]="\'lookups-backend-row-\' + product.sku">\n                  <td>{{ product.sku }}</td>\n                  <td>{{ product.name }}</td>\n                  <td [attr.data-testid]="\'lookups-backend-category-\' + product.sku">\n                    {{\n                      product.categoryKey | hexguardLookupLabel: \'categories\' : \'Unknown category\'\n                    }}\n                  </td>\n                  <td [attr.data-testid]="\'lookups-backend-supplier-\' + product.sku">\n                    {{\n                      product.supplierKey | hexguardLookupLabel: \'suppliers\' : \'Unknown supplier\'\n                    }}\n                  </td>\n                  <td [attr.data-testid]="\'lookups-backend-lifecycle-\' + product.sku">\n                    {{\n                      product.lifecycleKey\n                        | hexguardLookupLabel: \'lifecycleStates\' : \'Unknown lifecycle state\'\n                    }}\n                  </td>\n                </tr>\n              }\n            </tbody>\n          </table>\n        </div>\n      </section>\n    </div>\n  </article>\n\n  <demo-inspector-panel\n    demoAside\n    panelTestId="lookups-backend-inspector-panel"\n    snapshotTestId="lookups-backend-snapshot-json"\n    codeTestId="lookups-backend-code-sample"\n    title="Live sample API state and real component source"\n    summary="The snapshot includes the selected API origin, scenario, request URL, and the labels resolved from the last successful backend catalog."\n    [snapshotJson]="snapshotJson()"\n    [docsLinks]="demo.docsLinks"\n    [snippetId]="demo.codeSample.snippetId"\n  />\n</demo-page-layout>',
