        code: '.lookups-toolbar {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 0.75rem;\n  justify-content: flex-end;\n}\n\n.lookups-connection-grid,\n.lookups-action-row {\n  display: grid;\n  gap: 0.75rem;\n}\n\n.lookups-banner {\n  margin: 0;\n  padding: 0.875rem 1rem;\n  border-radius: 0.9rem;\n  background: #fff4db;\n  color: #725004;\n}\n\n.lookups-banner--warning {\n  border: 1px solid #e0c37d;\n}\n\n.lookups-request-url {\n  margin: 0;\n  color: #35506b;\n  overflow-wrap: anywhere;\n}\n\n.lookups-surface-grid {\n  display: grid;\n  gap: 1rem;\n}\n\n.lookups-surface-card {\n  display: grid;\n  gap: 0.9rem;\n  padding: 1.25rem;\n  border-radius: 1rem;\n  background: #f7fafc;\n}\n\n.lookups-selection-list {\n  margin: 0;\n  padding-left: 1.1rem;\n  display: grid;\n  gap: 0.5rem;\n}\n\n.lookups-table-shell {\n  overflow-x: auto;\n}\n\n.lookups-table {\n  width: 100%;\n  border-collapse: collapse;\n}\n\n.lookups-table th,\n.lookups-table td {\n  padding: 0.75rem 0.65rem;\n  border-bottom: 1px solid #d9e1ea;\n  text-align: left;\n  vertical-align: top;\n}\n\n@media (min-width: 900px) {\n  .lookups-connection-grid {\n    grid-template-columns: repeat(2, minmax(0, 1fr));\n  }\n\n  .lookups-action-row {\n    grid-auto-flow: column;\n    justify-content: start;\n    grid-auto-columns: max-content;\n  }\n\n  .lookups-surface-grid {\n    grid-template-columns: minmax(0, 1fr) minmax(0, 1.25fr);\n  }\n}',
