        code: '<demo-page-layout testId="lookups-summary-page">\n  <demo-navigation-strip demoNavigation testId="lookups-summary-demo-navigation" [demo]="demo" />\n\n  <article demoIntro class="demo-card demo-card--stack" data-testid="lookups-summary-intro-card">\n    <div class="demo-card__header">\n      <div>\n        <p class="demo-eyebrow">Angular Lookups</p>\n        <h2>Shared keys resolve into stable labels across detail and table surfaces.</h2>\n      </div>\n\n      <div class="lookups-toolbar">\n        <span class="demo-hint-pill" data-testid="lookups-summary-version-pill">\n          Version: {{ lookups.version() ?? \'not loaded\' }}\n        </span>\n        <span class="demo-hint-pill" data-testid="lookups-summary-request-count-pill">\n          Requests: {{ repository.loadCount() }}\n        </span>\n      </div>\n    </div>\n\n    <p class="demo-card__summary">\n      The grid renders labels through <code>HexguardLookupLabelPipe</code> while the inspector still\n      shows the same labels resolved imperatively from <code>injectLookups()</code>.\n    </p>\n\n    <div class="lookups-action-row">\n      <button\n        type="button"\n        class="demo-button"\n        data-testid="lookups-summary-load-button"\n        [disabled]="isBusy()"\n        (click)="loadBaseCatalog()"\n      >\n        Load base catalog\n      </button>\n      <button\n        type="button"\n        class="demo-button demo-button--ghost"\n        data-testid="lookups-summary-refresh-button"\n        [disabled]="isBusy()"\n        (click)="reloadRefreshedCatalog()"\n      >\n        Reload refreshed labels\n      </button>\n      <button\n        type="button"\n        class="demo-button demo-button--ghost"\n        data-testid="lookups-summary-invalidate-button"\n        (click)="invalidateCatalog()"\n      >\n        Invalidate cache\n      </button>\n    </div>\n\n    @if (errorMessage(); as errorMessage) {\n      <p class="lookups-banner lookups-banner--warning" data-testid="lookups-summary-error">\n        {{ errorMessage }}\n      </p>\n    }\n\n    <demo-status-strip\n      testId="lookups-summary-status-strip"\n      summaryTestId="lookups-summary-summary"\n      urlTestId="lookups-summary-current-url"\n      [summary]="statusSummary()"\n      [currentUrl]="currentUrl()"\n    />\n  </article>\n\n  <article demoPrimary class="demo-card demo-card--stack" data-testid="lookups-summary-grid-card">\n    <div class="lookups-surface-grid">\n      <section class="lookups-surface-card" data-testid="lookups-summary-grid">\n        <p class="demo-eyebrow">Template labels</p>\n        <h3>One grid uses the pipe to resolve shared catalog values</h3>\n\n        <div class="lookups-table-shell">\n          <table class="lookups-table">\n            <thead>\n              <tr>\n                <th scope="col">SKU</th>\n                <th scope="col">Product</th>\n                <th scope="col">Category</th>\n                <th scope="col">Supplier</th>\n                <th scope="col">Lifecycle</th>\n              </tr>\n            </thead>\n            <tbody>\n              @for (product of products; track product.sku) {\n                <tr [attr.data-testid]="\'lookups-summary-row-\' + product.sku">\n                  <td>{{ product.sku }}</td>\n                  <td>{{ product.name }}</td>\n                  <td [attr.data-testid]="\'lookups-summary-category-\' + product.sku">\n                    {{\n                      product.categoryKey | hexguardLookupLabel: \'categories\' : \'Unknown category\'\n                    }}\n                  </td>\n                  <td [attr.data-testid]="\'lookups-summary-supplier-\' + product.sku">\n                    {{\n                      product.supplierKey | hexguardLookupLabel: \'suppliers\' : \'Unknown supplier\'\n                    }}\n                  </td>\n                  <td [attr.data-testid]="\'lookups-summary-lifecycle-\' + product.sku">\n                    {{\n                      product.lifecycleKey\n                        | hexguardLookupLabel: \'lifecycleStates\' : \'Unknown lifecycle state\'\n                    }}\n                  </td>\n                </tr>\n              }\n            </tbody>\n          </table>\n        </div>\n      </section>\n\n      <section class="lookups-surface-card" data-testid="lookups-summary-resolution-panel">\n        <p class="demo-eyebrow">Resolved snapshot</p>\n        <h3>Imperative reads match the same labels used in the table</h3>\n\n        <ul class="lookups-resolution-list">\n          @for (row of resolvedRows(); track row.sku) {\n            <li [attr.data-testid]="\'lookups-summary-resolved-\' + row.sku">\n              <strong>{{ row.sku }}</strong\n              >: {{ row.category }} / {{ row.supplier }} /\n              {{ row.lifecycle }}\n            </li>\n          }\n        </ul>\n\n        <p class="demo-card__summary">\n          The third row intentionally keeps a missing supplier key so fallback rendering stays\n          explicit instead of silently fabricating a label.\n        </p>\n      </section>\n    </div>\n  </article>\n\n  <demo-inspector-panel\n    demoAside\n    panelTestId="lookups-summary-inspector-panel"\n    snapshotTestId="lookups-summary-snapshot-json"\n    codeTestId="lookups-summary-code-sample"\n    title="Resolved labels and real component source"\n    summary="The snapshot shows the exact labels resolved for each row, including explicit fallback handling for a missing supplier key."\n    [snapshotJson]="snapshotJson()"\n    [docsLinks]="demo.docsLinks"\n    [snippetId]="demo.codeSample.snippetId"\n  />\n</demo-page-layout>',
