        id: 'css',
        label: 'styles.css',
        language: 'css',
        sourcePath:
          'angular/apps/demo-angular/src/app/features/packages/angular/angular-permissions/pages/permission-actions-demo-page/permission-actions-demo-page.component.css',
        code: '.permissions-persona-grid {\n  display: grid;\n  gap: 1rem;\n  grid-template-columns: minmax(18rem, 24rem) minmax(0, 1fr);\n}\n\n.permissions-persona-grid__select {\n  min-width: 0;\n}\n\n.permissions-summary-card {\n  border: 1px solid var(--demo-border, #d7dde4);\n  border-radius: 1.15rem;\n  padding: 1.05rem 1.15rem;\n  background: color-mix(in srgb, var(--demo-surface, #ffffff) 92%, white);\n  box-shadow: var(--shadow-soft);\n}\n\n.permissions-action-grid {\n  display: grid;\n  gap: 1rem;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n}\n\n.permissions-surface-card {\n  border: 1px solid var(--demo-border, #d7dde4);\n  border-radius: 1.15rem;\n  padding: 1.05rem 1.15rem;\n  background: color-mix(in srgb, var(--demo-surface, #ffffff) 94%, white);\n  box-shadow: var(--shadow-soft);\n}\n\n.permissions-surface-card--success {\n  background: linear-gradient(\n    180deg,\n    color-mix(in srgb, #e9fbf0 78%, var(--demo-surface, #ffffff)),\n    color-mix(in srgb, #dff5ea 62%, white)\n  );\n}\n\n.permissions-surface-card--warning {\n  background: linear-gradient(\n    180deg,\n    color-mix(in srgb, #fff4dc 82%, var(--demo-surface, #ffffff)),\n    color-mix(in srgb, #fde8c5 56%, white)\n  );\n}\n\n.permissions-button-row {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 0.8rem;\n  margin-top: 1rem;\n}\n\n.permissions-access-list {\n  margin: 1rem 0 0;\n  padding-left: 1.2rem;\n}\n\n.permissions-chip-row {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 0.6rem;\n  margin-top: 0.65rem;\n}\n\n@media (max-width: 900px) {\n  .permissions-persona-grid,\n  .permissions-action-grid {\n    grid-template-columns: 1fr;\n  }\n}',
