        code: ':host {\n  display: block;\n}\n\n/* ── Controls ─────────────────────────────── */\n\n.bulk-toolbar {\n  display: flex;\n  gap: 0.5rem;\n  align-items: center;\n  flex-wrap: wrap;\n}\n\n.bulk-controls-grid {\n  display: grid;\n  gap: 0.5rem;\n  grid-template-columns: repeat(auto-fit, minmax(11rem, 1fr));\n}\n\n/* ── Data table ───────────────────────────── */\n\n.bulk-table-wrap {\n  overflow-x: auto;\n  border: 1px solid var(--color-border);\n  border-radius: 1rem;\n  background: var(--color-surface-strong);\n}\n\n.bulk-table {\n  width: 100%;\n  border-collapse: collapse;\n  font-size: 0.87rem;\n}\n\n.bulk-table th {\n  padding: 0.65rem 0.75rem;\n  text-align: left;\n  font-family: var(--font-mono);\n  font-size: 0.72rem;\n  font-weight: 600;\n  letter-spacing: 0.06em;\n  text-transform: uppercase;\n  color: var(--color-muted);\n  border-bottom: 1px solid var(--color-border);\n  background: rgba(255, 252, 248, 0.6);\n}\n\n.bulk-table td {\n  padding: 0.55rem 0.75rem;\n  border-bottom: 1px solid var(--color-border);\n  color: var(--color-ink);\n}\n\n.bulk-table tbody tr:last-child td {\n  border-bottom: none;\n}\n\n.bulk-table tbody tr:hover {\n  background: rgba(20, 101, 111, 0.04);\n}\n\n.bulk-table__check {\n  width: 2.5rem;\n  text-align: center;\n}\n\n.bulk-table__check input {\n  width: 1rem;\n  height: 1rem;\n  cursor: pointer;\n  accent-color: var(--color-accent);\n}\n\n.bulk-table__row--selected {\n  background: rgba(20, 101, 111, 0.06);\n}\n\n.bulk-status {\n  display: inline-block;\n  padding: 0.1rem 0.45rem;\n  border-radius: 0.3rem;\n  font-family: var(--font-mono);\n  font-size: 0.75rem;\n  font-weight: 500;\n}\n\n.bulk-status--pending {\n  background: rgba(20, 101, 111, 0.08);\n  color: var(--color-accent-strong);\n}\n\n.bulk-status--shipped {\n  background: rgba(34, 197, 94, 0.1);\n  color: #166534;\n}\n\n.bulk-status--cancelled {\n  background: rgba(217, 119, 75, 0.1);\n  color: #a35832;\n}\n\n/* ── Results ──────────────────────────────── */\n\n.bulk-results {\n  display: grid;\n  gap: var(--space-card-gap);\n  padding: var(--space-card-pad);\n  margin-top: var(--space-grid);\n  border: 1px solid var(--color-border);\n  border-radius: var(--radius-card);\n  background: linear-gradient(180deg, rgba(255, 255, 255, 0.88), rgba(250, 244, 236, 0.72));\n}\n\n.bulk-results__grid {\n  display: grid;\n  gap: var(--space-grid);\n  grid-template-columns: repeat(auto-fit, minmax(min(16rem, 100%), 1fr));\n}\n\n.bulk-result-block {\n  display: grid;\n  gap: 0.5rem;\n  padding: var(--space-card-pad);\n  border: 1px solid var(--color-border);\n  border-radius: 0.85rem;\n  background: var(--color-surface-strong);\n}\n\n.bulk-result-block__header {\n  display: flex;\n  gap: 0.5rem;\n  align-items: center;\n  justify-content: space-between;\n}\n\n.bulk-result-block__header strong {\n  font-size: 0.9rem;\n}\n\n.bulk-result-list {\n  display: grid;\n  gap: 0.3rem;\n  margin: 0;\n  padding: 0;\n  list-style: none;\n}\n\n.bulk-result-item {\n  display: flex;\n  gap: 0.4rem;\n  align-items: center;\n  padding: 0.35rem 0.5rem;\n  border-radius: 0.4rem;\n  font-size: 0.82rem;\n  background: rgba(34, 197, 94, 0.06);\n}\n\n.bulk-result-item--fail {\n  background: rgba(217, 119, 75, 0.08);\n}\n\n.bulk-result-item__icon {\n  flex-shrink: 0;\n  width: 1.1rem;\n  text-align: center;\n  font-weight: 700;\n}\n\n.bulk-result-item--fail .bulk-result-item__icon {\n  color: #a35832;\n}\n\n.bulk-result-item__error {\n  color: var(--color-muted);\n  font-size: 0.78rem;\n}\n\n/* ── Responsive ───────────────────────────── */\n\n@media (max-width: 720px) {\n  .bulk-controls-grid {\n    grid-template-columns: 1fr;\n  }\n}',
