        id: 'css',
        label: 'styles.css',
        language: 'css',
        sourcePath:
          'angular/apps/demo-angular/src/app/features/packages/angular/angular-clipboard/pages/clipboard-demo-page/clipboard-demo-page.component.css',
        code: '.clipboard-controls {\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n}\n\n.clipboard-input {\n  padding: 0.625rem 0.75rem;\n  border: 1px solid var(--color-border);\n  border-radius: 0.65rem;\n  font-size: 0.925rem;\n  outline: none;\n  font-family: var(--font-display);\n}\n\n.clipboard-input:focus {\n  border-color: var(--color-accent-strong);\n  box-shadow: 0 0 0 2px var(--color-accent-soft);\n}\n\n.clipboard-actions {\n  display: flex;\n  gap: 0.75rem;\n  flex-wrap: wrap;\n}\n\n.clipboard-error {\n  color: var(--color-highlight);\n  font-size: 0.875rem;\n  margin: 0;\n}\n\n.clipboard-success {\n  color: #2e7d32;\n  font-size: 0.875rem;\n  margin: 0;\n}\n\n.clipboard-history {\n  margin-top: 0.5rem;\n  padding: 0.75rem;\n  background: var(--surface-alt, #f9f9f9);\n  border-radius: 4px;\n}\n\n.clipboard-history h4 {\n  margin: 0 0 0.5rem;\n  font-size: 0.875rem;\n}\n\n.clipboard-history ol {\n  margin: 0;\n  padding-left: 1.25rem;\n  font-size: 0.8125rem;\n}\n\n.clipboard-history li {\n  padding: 0.125rem 0;\n}',
