  'angular-wizard-state/demo-state': {
    id: 'angular-wizard-state/demo-state',
    title: 'Wizard State demo component source',
    description:
      'Generated from the real Wizard State demo component files, including TypeScript, template, and styles.',
    files: [
      {
        id: 'ts',
        label: 'component.ts',
        language: 'ts',
        sourcePath:
          'angular/apps/demo-angular/src/app/features/packages/angular/angular-wizard-state/pages/wizard-state-demo-page/wizard-state-demo-page.component.ts',
        code: "import { ChangeDetectionStrategy, Component, computed, signal } from '@angular/core';\nimport { injectWizardState } from '@hexguard/angular-wizard-state';\nimport type { WizardStep } from '@hexguard/angular-wizard-state';\nimport { ANGULAR_WIZARD_STATE_DEMO } from '../../../../../../demo-registry';\nimport { DemoInspectorPanelComponent } from '../../../../../../shared/components/demo-inspector-panel.component';\nimport { DemoNavigationStripComponent } from '../../../../../../shared/components/demo-navigation-strip.component';\nimport { DemoPageLayoutComponent } from '../../../../../../shared/components/demo-page-layout.component';\nimport { DemoStatusStripComponent } from '../../../../../../shared/components/demo-status-strip.component';\nimport { formatSnapshot } from '../../../../../../shared/formatting';\n\n@Component({\n  standalone: true,\n  selector: 'demo-wizard-state-demo-page',\n  templateUrl: './wizard-state-demo-page.component.html',\n  styleUrl: './wizard-state-demo-page.component.css',\n  imports: [\n    DemoInspectorPanelComponent,\n    DemoNavigationStripComponent,\n    DemoPageLayoutComponent,\n    DemoStatusStripComponent,\n  ],\n  changeDetection: ChangeDetectionStrategy.OnPush,\n})\nexport class WizardStateDemoPageComponent {\n  protected readonly demo = ANGULAR_WIZARD_STATE_DEMO;\n  protected readonly agree = signal(false);\n\n  private readonly steps: readonly WizardStep[] = [\n    { id: 'details', title: 'Details' },\n    { id: 'config', title: 'Configuration', validate: this.agree.asReadonly() },\n    { id: 'review', title: 'Review' },\n  ];\n\n  protected readonly wizard = injectWizardState({ steps: this.steps });\n\n  protected readonly snapshotJson = computed(() =>\n    formatSnapshot({\n      currentStep: this.wizard.currentStep()?.id,\n      currentIndex: this.wizard.currentIndex(),\n      isFirst: this.wizard.isFirst(),\n      isLast: this.wizard.isLast(),\n      canGoNext: this.wizard.canGoNext(),\n      canGoBack: this.wizard.canGoBack(),\n      progress: this.wizard.progress(),\n      isFinished: this.wizard.isFinished(),\n    }),\n  );\n}",
      },
      {
        id: 'html',
        label: 'template.html',
        language: 'html',
        sourcePath:
          'angular/apps/demo-angular/src/app/features/packages/angular/angular-wizard-state/pages/wizard-state-demo-page/wizard-state-demo-page.component.html',
        code: '<demo-page-layout testId="wizard-state-demo">\n  <demo-navigation-strip demoNavigation testId="wizard-state-demo-navigation" [demo]="demo" />\n  <article demoIntro class="demo-card demo-card--stack">\n    <div class="demo-card__header">\n      <div>\n        <p class="demo-eyebrow">Angular Wizard State</p>\n        <h2>Multi-step flow state for Angular.</h2>\n      </div>\n    </div>\n    <demo-status-strip\n      testId="wizard-state-demo-status"\n      summary="Multi-step flow with validation gates: navigate through Details, Configuration, and Review."\n      currentUrl="Angular Wizard State — Demo"\n      summaryTestId="wizard-state-demo-summary"\n      urlTestId="wizard-state-demo-url"\n    />\n  </article>\n  <article demoPrimary class="demo-card demo-card--stack" data-testid="wizard-state-playground">\n    <!-- demo-snippet:start angular-wizard-state/demo-state -->\n    <h3>Wizard: {{ wizard.currentStep()?.title }}</h3>\n\n    @if (wizard.isFinished()) {\n      <div class="wizard-finished" data-testid="wizard-finished">\n        <p>✅ Wizard completed!</p>\n        <button class="demo-button" (click)="wizard.reset()" data-testid="btn-reset">Reset</button>\n      </div>\n    } @else {\n      <div class="wizard-step" data-testid="wizard-step">\n        @if (wizard.currentStep()?.id === \'details\') {\n          <p>Enter the basic details for this item.</p>\n        }\n        @if (wizard.currentStep()?.id === \'config\') {\n          <p>Configure your settings:</p>\n          <label class="wizard-checkbox">\n            <input\n              type="checkbox"\n              [checked]="agree()"\n              (change)="agree.set(!agree())"\n              data-testid="chk-agree"\n            />\n            I agree to the terms (enables Next)\n          </label>\n        }\n        @if (wizard.currentStep()?.id === \'review\') {\n          <p>Review your choices and confirm.</p>\n        }\n      </div>\n\n      <div class="wizard-progress">\n        <div class="progress-bar">\n          <div class="progress-fill" [style.width.%]="wizard.progress()"></div>\n        </div>\n        <span class="progress-label" data-testid="progress-label">{{ wizard.progress() }}%</span>\n      </div>\n\n      <div class="demo-actions-row">\n        <button\n          class="demo-button"\n          [disabled]="!wizard.canGoBack()"\n          (click)="wizard.back()"\n          data-testid="btn-back"\n        >\n          Back\n        </button>\n        <button\n          class="demo-button"\n          [disabled]="!wizard.canGoNext()"\n          (click)="wizard.next()"\n          data-testid="btn-next"\n        >\n          Next\n        </button>\n        <button class="demo-button demo-button--ghost" (click)="wizard.finish()" data-testid="btn-finish">\n          Finish\n        </button>\n        <button class="demo-button demo-button--ghost" (click)="wizard.cancel()" data-testid="btn-cancel">\n          Cancel\n        </button>\n      </div>\n    }\n    <!-- demo-snippet:end -->\n  </article>\n  <demo-inspector-panel\n    demoAside\n    panelTestId="wizard-state-inspector-panel"\n    title="Wizard State snapshot"\n    [snapshotJson]="snapshotJson()"\n    [snippetId]="demo.codeSample.snippetId"\n    [docsLinks]="demo.docsLinks"\n    snapshotTestId="wizard-state-snapshot-json"\n    codeTestId="wizard-state-code-sample"\n  />\n</demo-page-layout>',
      },
      {
        id: 'css',
        label: 'styles.css',
        language: 'css',
        sourcePath:
          'angular/apps/demo-angular/src/app/features/packages/angular/angular-wizard-state/pages/wizard-state-demo-page/wizard-state-demo-page.component.css',
        code: '.wizard-step {\n  padding: 1rem;\n  margin: 1rem 0;\n  background: var(--color-accent-soft);\n  border-radius: 0.65rem;\n  min-height: 60px;\n}\n\n.wizard-finished {\n  padding: 2rem;\n  text-align: center;\n  font-size: 1.2rem;\n}\n\n.wizard-checkbox {\n  display: flex;\n  align-items: center;\n  gap: 0.5rem;\n  margin-top: 0.5rem;\n  cursor: pointer;\n}\n\n.wizard-progress {\n  display: flex;\n  align-items: center;\n  gap: 0.75rem;\n  margin: 1rem 0;\n}\n\n.progress-bar {\n  flex: 1;\n  height: 8px;\n  background: var(--color-border);\n  border-radius: 4px;\n  overflow: hidden;\n}\n\n.progress-fill {\n  height: 100%;\n  background: var(--color-accent);\n  border-radius: 4px;\n  transition: width 0.3s ease;\n}\n\n.progress-label {\n  font-size: 0.875rem;\n  font-weight: 600;\n  min-width: 3rem;\n  text-align: right;\n}',
      },
    ],
  },
