        code: '<demo-page-layout testId="command-palette-demo">\n  <demo-navigation-strip demoNavigation testId="command-palette-demo-navigation" [demo]="demo" />\n  <article demoIntro class="demo-card demo-card--stack">\n    <div class="demo-card__header">\n      <div>\n        <p class="demo-eyebrow">Angular Command Palette</p>\n        <h2>Headless command registry for Angular.</h2>\n      </div>\n    </div>\n    <demo-status-strip\n      testId="command-palette-demo-status"\n      summary="Register, search, and invoke commands with keyboard shortcut support."\n      currentUrl="Angular Command Palette — Demo"\n      summaryTestId="command-palette-demo-summary"\n      urlTestId="command-palette-demo-url"\n    />\n  </article>\n  <article demoPrimary class="demo-card demo-card--stack" data-testid="command-palette-playground">\n    <!-- demo-snippet:start angular-command-palette/demo-state -->\n    <div class="palette-controls">\n      <button\n        class="demo-button"\n        (click)="registry.togglePalette()"\n        data-testid="btn-toggle-palette"\n      >\n        {{ registry.paletteOpen() ? \'Close\' : \'Open\' }} Palette\n      </button>\n    </div>\n\n    @if (registry.paletteOpen()) {\n      <div class="palette-overlay" data-testid="palette-overlay">\n        <input\n          class="palette-input"\n          type="text"\n          placeholder="Search commands..."\n          [value]="query()"\n          (input)="query.set($any($event.target).value)"\n          data-testid="palette-search"\n          autofocus\n        />\n        <ul class="palette-results">\n          @for (cmd of filteredCommands; track cmd.id) {\n            <li class="palette-item" (click)="invokeCommand(cmd)" data-testid="palette-item">\n              <span class="palette-item-title">{{ cmd.title }}</span>\n              @if (cmd.shortcut) {\n                <span class="palette-item-shortcut">{{ cmd.shortcut }}</span>\n              }\n              @if (cmd.category) {\n                <span class="palette-item-category">{{ cmd.category }}</span>\n              }\n            </li>\n          } @empty {\n            <li class="palette-empty">No commands found</li>\n          }\n        </ul>\n      </div>\n    }\n\n    <p class="last-invoked" data-testid="last-invoked">\n      Last invoked: <strong>{{ lastInvoked() || \'None\' }}</strong>\n    </p>\n    <!-- demo-snippet:end -->\n  </article>\n  <demo-inspector-panel\n    demoAside\n    panelTestId="command-palette-inspector-panel"\n    title="Command Palette snapshot"\n    [snapshotJson]="snapshotJson()"\n    [snippetId]="demo.codeSample.snippetId"\n    [docsLinks]="demo.docsLinks"\n    snapshotTestId="command-palette-snapshot-json"\n    codeTestId="command-palette-code-sample"\n  />\n</demo-page-layout>',
