        code: '.palette-controls {\n  margin-bottom: 1rem;\n}\n\n.palette-overlay {\n  border: 1px solid var(--color-border);\n  border-radius: 0.65rem;\n  overflow: hidden;\n  box-shadow: var(--shadow-soft);\n}\n\n.palette-input {\n  width: 100%;\n  padding: 0.75rem 1rem;\n  border: none;\n  border-bottom: 1px solid var(--color-border);\n  font-size: 1rem;\n  outline: none;\n  box-sizing: border-box;\n  font-family: var(--font-display);\n}\n\n.palette-results {\n  list-style: none;\n  margin: 0;\n  padding: 0;\n  max-height: 300px;\n  overflow-y: auto;\n}\n\n.palette-item {\n  display: flex;\n  align-items: center;\n  gap: 0.75rem;\n  padding: 0.625rem 1rem;\n  cursor: pointer;\n  transition: background 0.1s;\n}\n\n.palette-item:hover {\n  background: var(--color-accent-soft);\n}\n\n.palette-item-title {\n  flex: 1;\n  font-weight: 500;\n}\n\n.palette-item-shortcut {\n  font-size: 0.75rem;\n  color: var(--color-muted);\n  background: var(--color-surface);\n  padding: 0.125rem 0.375rem;\n  border-radius: 0.35rem;\n}\n\n.palette-item-category {\n  font-size: 0.75rem;\n  color: var(--color-muted);\n}\n\n.palette-empty {\n  padding: 1rem;\n  text-align: center;\n  color: var(--color-muted);\n}\n\n.last-invoked {\n  margin-top: 1rem;\n  font-size: 0.9rem;\n}',
