        code: '<demo-page-layout testId="recently-viewed-demo">\n  <demo-navigation-strip demoNavigation testId="recently-viewed-demo-navigation" [demo]="demo" />\n  <article demoIntro class="demo-card demo-card--stack">\n    <div class="demo-card__header">\n      <div>\n        <p class="demo-eyebrow">Angular Recently Viewed</p>\n        <h2>Recently-viewed item tracking with dedup, metadata, and route support.</h2>\n      </div>\n    </div>\n    <demo-status-strip testId="recently-viewed-demo-status" summary="Add items with metadata, test dedup strategies, navigate routes." currentUrl="Angular Recently Viewed — Demo" summaryTestId="recently-viewed-demo-summary" urlTestId="recently-viewed-demo-url" />\n  </article>\n  <article demoPrimary class="demo-card demo-card--stack" data-testid="recently-viewed-playground">\n    <div class="demo-controls">\n      <button class="demo-button" (click)="addItem()" data-testid="add-btn">Add Item</button>\n      <button class="demo-button demo-button--ghost" (click)="recent.clear()" data-testid="clear-btn">Clear All</button>\n    </div>\n    <div class="demo-controls">\n      <button class="demo-button demo-button--ghost" (click)="addDuplicate()" data-testid="add-dup-btn">Test Dedup</button>\n      <span class="demo-hint">Adds same ID twice — observe dedup behavior</span>\n    </div>\n    <div class="demo-controls">\n      <label>Remove by ID:\n        <input #removeInput class="demo-input" data-testid="remove-input" />\n      </label>\n      <button class="demo-button demo-button--ghost" (click)="recent.remove(removeInput.value); removeInput.value=\'\'" data-testid="remove-btn">Remove</button>\n    </div>\n    <p class="demo-subtitle">Items ({{ recent.count() }}):</p>\n    @if (recent.items().length === 0) {\n      <p class="demo-empty">No recent items. Click "Add Item" to start.</p>\n    }\n    <ul class="recent-list" data-testid="recent-list">\n      @for (item of recent.items(); track item.id) {\n        <li class="recent-item" data-testid="recent-item">\n          <span class="recent-label">{{ item.label }}</span>\n          @if (item.route) { <span class="recent-route">→ {{ item.route }}</span> }\n          @if (item.meta; as m) { <span class="recent-meta">[{{ getMetaCategory(m) }}]</span> }\n          <button class="recent-remove" (click)="recent.remove(item.id)" title="Remove">×</button>\n        </li>\n      }\n    </ul>\n  </article>\n  <demo-inspector-panel demoAside panelTestId="recently-viewed-inspector-panel" title="Recently Viewed snapshot" [snapshotJson]="snapshotJson()" [snippetId]="demo.codeSample.snippetId" [docsLinks]="demo.docsLinks" snapshotTestId="recently-viewed-snapshot-json" codeTestId="recently-viewed-code-sample" />\n</demo-page-layout>',
