        language: 'css',
        sourcePath:
          'angular/apps/demo-angular/src/app/features/packages/angular/angular-form-utils/pages/form-utils-demo-page/form-utils-demo-page.component.css',
        code: '.demo-fieldset { border: 1px solid var(--color-border, #ddd); border-radius: 6px; padding: 1rem; margin-bottom: 1rem; }\n.demo-fieldset legend { font-weight: 600; padding: 0 0.5rem; }\n.demo-fieldset label { display: block; margin-bottom: 0.4rem; }\n.demo-fieldset input, .demo-fieldset select { margin-left: 0.5rem; padding: 0.3rem; border: 1px solid var(--color-border, #ccc); border-radius: 4px; }\n.demo-error { color: var(--color-error, #d32f2f); font-size: 0.85em; margin: 0.25rem 0; }\n.demo-success { color: var(--color-success, #2e7d32); font-size: 0.85em; margin: 0.25rem 0; }\n.demo-dirty-controls { display: flex; align-items: center; gap: 0.5rem; margin-top: 0.5rem; flex-wrap: wrap; font-size: 0.85em; }\n.demo-hint { font-size: 0.85em; color: var(--color-text-secondary, #666); margin: 0 0 0.5rem; }\n.demo-nested { border: 1px dashed var(--color-border, #ccc); border-radius: 4px; padding: 0.5rem; margin-top: 0.5rem; }\n.demo-errors-json { background: var(--color-surface, #f5f5f5); padding: 0.5rem; border-radius: 4px; font-size: 0.85em; max-height: 120px; overflow: auto; }\n.demo-pending { color: var(--color-warning, #f57c00); font-size: 0.85em; margin: 0.25rem 0; }\n.demo-tags { display: flex; gap: 0.4rem; flex-wrap: wrap; margin-top: 0.5rem; }\n.demo-tag { display: inline-flex; align-items: center; gap: 0.25rem; background: var(--color-surface, #e3f2fd); padding: 0.15rem 0.5rem; border-radius: 12px; font-size: 0.85em; }\n.tag-remove { cursor: pointer; border: none; background: none; color: var(--color-error, #d32f2f); font-size: 1em; line-height: 1; }\n.tag-move { cursor: pointer; border: none; background: none; color: var(--color-accent, #1976d2); font-size: 0.75em; line-height: 1; padding: 0 0.1rem; }\n.tag-move:disabled { opacity: 0.3; cursor: default; }',
