        code: '<demo-page-layout testId="query-signal-forms-demo">\n  <demo-navigation-strip demoNavigation testId="query-signal-forms-demo-navigation" [demo]="demo" />\n  <article demoIntro class="demo-card demo-card--stack">\n    <div class="demo-card__header">\n      <div>\n        <p class="demo-eyebrow">Angular Query Signal Forms</p>\n        <h2>Signal-based reactive forms with URL-synced query state.</h2>\n      </div>\n    </div>\n    <demo-status-strip testId="query-signal-forms-demo-status" summary="Toggle sync mode, patch values, commit/revert in manual mode. Codecs: string, number, enum, boolean, array, date." currentUrl="Angular Query Signal Forms — Demo" summaryTestId="query-signal-forms-demo-summary" urlTestId="query-signal-forms-demo-url" />\n  </article>\n  <article demoPrimary class="demo-card demo-card--stack" data-testid="query-signal-forms-playground">\n    <!-- Sync Mode Toggle -->\n    <div class="demo-controls">\n      <label class="demo-toggle">\n        <input type="checkbox" [checked]="syncMode() === \'manual\'" (change)="toggleMode()" data-testid="sync-mode-toggle" />\n        Manual sync mode\n      </label>\n      <span class="demo-hint">Current: <strong>{{ syncMode() }}</strong></span>\n    </div>\n\n    <!-- Form fields (live-binding via wrapper methods) -->\n    @let snap = query().snapshot();\n\n    <fieldset class="demo-fieldset">\n      <legend>Filter Controls (all mapped to URL query params)</legend>\n\n      <label>Search:\n        <input [value]="snap.search" (input)="patch({ search: $any($event.target).value })" data-testid="search-input" />\n      </label>\n\n      <label>Page:\n        <input type="number" [value]="snap.page" (input)="patch({ page: +$any($event.target).value })" data-testid="page-input" />\n      </label>\n\n      <label>Status:\n        <select [value]="snap.status" (change)="patch({ status: $any($event.target).value })" data-testid="status-select">\n          <option value="all">All</option>\n          <option value="open">Open</option>\n          <option value="closed">Closed</option>\n        </select>\n      </label>\n\n      <label>Priority:\n        <select [value]="snap.priority" (change)="patch({ priority: $any($event.target).value })" data-testid="priority-select">\n          <option value="low">Low</option>\n          <option value="medium">Medium</option>\n          <option value="high">High</option>\n        </select>\n      </label>\n\n      <label>Archived:\n        <input type="checkbox" [checked]="snap.archived" (change)="patch({ archived: $any($event.target).checked })" data-testid="archived-checkbox" />\n      </label>\n\n      <label>Due after:\n        <input type="date" [value]="formatDate(snap.dueAfter)" (change)="patch({ dueAfter: parseDate($any($event.target).value) })" data-testid="due-date-input" />\n      </label>\n\n      <label>Tags:\n        <input #tagInput data-testid="tag-input" />\n        <button class="demo-button demo-button--ghost" (click)="addTag(tagInput.value); tagInput.value=\'\'" data-testid="add-tag-btn">Add</button>\n      </label>\n      <div class="demo-tags">\n        @for (tag of snap.tags; track tag) {\n          <span class="demo-tag" data-testid="demo-tag">\n            {{ tag }}\n            <button class="tag-remove" (click)="removeTag(tag)" title="Remove tag">×</button>\n          </span>\n        }\n      </div>\n    </fieldset>\n\n    <!-- Manual sync controls -->\n    @if (syncMode() === \'manual\') {\n      <fieldset class="demo-fieldset demo-fieldset--manual">\n        <legend>Manual Sync Controls</legend>\n        <div class="demo-controls">\n          <button class="demo-button" (click)="commit()" data-testid="commit-btn">Commit</button>\n          <button class="demo-button demo-button--ghost" (click)="revert()" data-testid="revert-btn">Revert</button>\n          <button class="demo-button demo-button--ghost" (click)="reset()" data-testid="reset-btn">Reset All</button>\n          <span class="demo-hint">Pending: <strong [class.pending]="query().hasPendingChanges()" data-testid="pending-indicator">{{ query().hasPendingChanges() ? \'YES\' : \'no\' }}</strong></span>\n        </div>\n      </fieldset>\n    } @else {\n      <div class="demo-controls">\n        <button class="demo-button demo-button--ghost" (click)="reset()" data-testid="live-reset-btn">Reset All</button>\n      </div>\n    }\n  </article>\n  <demo-inspector-panel demoAside panelTestId="query-signal-forms-inspector-panel" title="Query snapshot" [snapshotJson]="snapshotJson()" [snippetId]="demo.codeSample.snippetId" [docsLinks]="demo.docsLinks" snapshotTestId="query-signal-forms-snapshot-json" codeTestId="query-signal-forms-code-sample" />\n</demo-page-layout>',
