        code: '.demo-fieldset { border: 1px solid var(--color-border, #ddd); border-radius: 6px; padding: 1rem; margin-bottom: 1rem; }\n.demo-fieldset legend { font-weight: 600; padding: 0 0.5rem; }\n.demo-fieldset label { display: block; margin-bottom: 0.5rem; }\n.demo-fieldset input, .demo-fieldset select { margin-left: 0.5rem; padding: 0.3rem; border: 1px solid var(--color-border, #ccc); border-radius: 4px; }\n.demo-fieldset input[type="checkbox"] { margin-left: 0; }\n.demo-fieldset input[type="number"] { width: 80px; }\n.demo-controls { display: flex; align-items: center; gap: 0.5rem; margin-bottom: 0.75rem; flex-wrap: wrap; }\n.demo-toggle { display: flex; align-items: center; gap: 0.4rem; cursor: pointer; }\n.demo-hint { font-size: 0.85em; color: var(--color-text-secondary, #666); }\n.pending { color: var(--color-warning, #f57c00); font-weight: 700; }\n.demo-tags { display: flex; gap: 0.4rem; flex-wrap: wrap; margin-top: 0.4rem; }\n.demo-tag { display: inline-flex; align-items: center; gap: 0.25rem; background: var(--color-surface, #e3f2fd); padding: 0.15rem 0.5rem; border-radius: 12px; font-size: 0.85em; }\n.tag-remove { cursor: pointer; border: none; background: none; color: var(--color-error, #d32f2f); font-size: 1em; line-height: 1; }\n.demo-fieldset--manual { border-color: var(--color-warning, #f57c00); background: var(--color-surface-warning, #fff3e0); }',
